-- [1/4971] ref=8435265309940 -> marca=Idempet
UPDATE llx_product_extrafields
SET    marca = 'Idempet'
WHERE  fk_object = (
           SELECT rowid FROM llx_product WHERE ref = '8435265309940'
       )
  AND  (marca IS NULL OR marca != 'Idempet');
INSERT IGNORE INTO llx_product_extrafields
    (fk_object, marca)
SELECT p.rowid, 'Idempet'
FROM   llx_product p
WHERE  p.ref = '8435265309940'
  AND  NOT EXISTS (
           SELECT 1 FROM llx_product_extrafields e
           WHERE  e.fk_object = p.rowid
       );

