SET    marca = 'SB'
WHERE  fk_object = (
           SELECT rowid FROM llx_product WHERE ref = 'SB TRIBIOTIC 400G'
       )
  AND  (marca IS NULL OR marca != 'SB');
INSERT IGNORE INTO llx_product_extrafields
    (fk_object, marca)
SELECT p.rowid, 'SB'
FROM   llx_product p
WHERE  p.ref = 'SB TRIBIOTIC 400G'
  AND  NOT EXISTS (
           SELECT 1 FROM llx_product_extrafields e
           WHERE  e.fk_object = p.rowid
       );

